class DataProcessor {
  int* data;
  size_t size;

public:
  DataProcessor(size_t n) : size(n) {
    data = new int[size];
    for (size_t i = 0; i < size; ++i) {
      data[i] = i * 2;
    }
  }

  ~DataProcessor() {
    delete[] data;
  }

  void process() {
    for (size_t i = 0; i < size; ++i) {
      if (data[i] % 2 == 0) {
        data[i] = data[i] / 2;
      } else {
        data[i] = data[i] * 3;
      }
    }
  }

  int sum() const {
    int total = 0;
    for (size_t i = 0; i < size; ++i) {
      total += data[i];
    }
    return total;
  }

  bool contains(int val) const {
    for (size_t i = 0; i < size; ++i) {
      if (data[i] == val) {
        return true;
      }
    }
    return false;
  }
};

